// Old mock constants removed - using real Claude API now

// Screening
const MMAP = {per:["per","PER"],pbr:["pbr","PBR"],roe:["roe","ROE"],divYield:["配当利回り","配当"],psr:["psr","PSR"],evEbitda:["ev/ebitda","EV/EBITDA"],fcfYield:["fcf利回り","FCF利回り"],roic:["roic","ROIC"],eqR:["自己資本比率"],deR:["de","DE","D/E","d/e"]};
function parseScr(q){const r=[];const re=/([A-Za-z/\u3000-\u9FFF]+)\s*(\d+\.?\d*)\s*(倍|%|兆円)?\s*(以上|以下|未満|超)/g;let m;while((m=re.exec(q))!==null){const t=m[1].trim(),v=parseFloat(m[2]),d=m[4];let k=null;for(const[key,al]of Object.entries(MMAP)){if(al.some(a=>t.toLowerCase().includes(a.toLowerCase())||a.includes(t))){k=key;break;}}if(k)r.push({m:k,op:(d==="以上"||d==="超")?">=":"<=",v,lb:`${t} ${v}${m[3]||""} ${d}`});}return r;}
// Screening logic is now inline in doSearch

// Components
function Bar({data,color="#22d3ee",h=120}){const mx=Math.max(...data.map(d=>Math.abs(d.v)),1);return(<div style={{display:"flex",alignItems:"flex-end",gap:3,height:h,width:"100%"}}>{data.map((d,i)=>(<div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:3}}><span style={{fontSize:10,color:"#94a3b8",fontVariantNumeric:"tabular-nums"}}>{Math.abs(d.v)>=10000?`${(d.v/1000).toFixed(0)}K`:d.v.toLocaleString()}</span><div style={{width:"100%",height:`${(Math.abs(d.v)/mx)*(h-28)}px`,background:d.v<0?`linear-gradient(180deg,#f8717144,#f8717120)`:`linear-gradient(180deg,${color},${color}44)`,borderRadius:"4px 4px 0 0",minHeight:3,transition:"height 0.5s ease"}}/><span style={{fontSize:8,color:"#64748b"}}>{d.l}</span></div>))}</div>);}

function Donut({segs}){const cols=["#22d3ee","#a78bfa","#f472b6","#34d399","#fbbf24","#fb923c"];let cum=0;const r=38,ci=2*Math.PI*r;return(<div style={{display:"flex",alignItems:"center",gap:14}}><svg width={92} height={92} viewBox="0 0 100 100">{segs.map((s,i)=>{const o=ci*(1-cum/100),ln=ci*(s.pct/100);cum+=s.pct;return <circle key={i} cx="50" cy="50" r={r} fill="none" stroke={cols[i%cols.length]} strokeWidth="11" strokeDasharray={`${ln} ${ci-ln}`} strokeDashoffset={o} transform="rotate(-90 50 50)"/>;})}</svg><div style={{display:"flex",flexDirection:"column",gap:2}}>{segs.map((s,i)=>(<div key={i} style={{display:"flex",alignItems:"center",gap:5,fontSize:11}}><div style={{width:7,height:7,borderRadius:2,background:cols[i%cols.length]}}/><span style={{color:"#94a3b8"}}>{s.name}</span><span style={{color:"#e2e8f0",fontWeight:600,marginLeft:"auto"}}>{s.pct}%</span></div>))}</div></div>);}

// Smart unit formatter - adapts to company size
function fmtVal(v, forceUnit) {
  if (v === 0) return "0";
  const abs = Math.abs(v);
  if (forceUnit === "百万円") return `${(v).toLocaleString()}百万`;
  if (abs >= 10000) return `${(v/10000).toFixed(abs>=100000?0:1)}兆`;
  if (abs >= 100) return `${v.toLocaleString()}億`;
  if (abs >= 1) return `${v.toFixed(1)}億`;
  return `${(v*100).toFixed(0)}百万`;
}
function autoUnit(revArr) {
  const mx = Math.max(...revArr.map(Math.abs));
  if (mx >= 10000) return { unit: "兆円", div: 10000, fmt: v => `${(v/10000).toFixed(mx>=100000?0:1)}` };
  if (mx >= 100) return { unit: "億円", div: 1, fmt: v => v.toLocaleString() };
  return { unit: "億円", div: 1, fmt: v => v.toFixed(1) };
}

// CAGR calculator
function calcCAGR(arr, years) {
  if (!arr || arr.length < 2) return null;
  const n = Math.min(years, arr.length - 1);
  const start = arr[arr.length - 1 - n];
  const end = arr[arr.length - 1];
  if (start <= 0 || end <= 0) return null;
  return (Math.pow(end / start, 1 / n) - 1) * 100;
}

// Tooltip-enabled metric value
function Mv({l, v, c, u, tip}) {
  const [show, setShow] = useState(false);
  return (
    <div style={{display:"flex",flexDirection:"column",gap:1,padding:"5px 0",position:"relative",cursor:tip?"help":"default"}}
      onMouseEnter={()=>tip&&setShow(true)} onMouseLeave={()=>setShow(false)}>
      <span style={{fontSize:9,color:"#475569"}}>{l}{tip&&<span style={{marginLeft:3,fontSize:8,color:"#334155"}}>ⓘ</span>}</span>
      <span style={{fontSize:14,fontWeight:700,color:c||"#e2e8f0",fontFamily:"'JetBrains Mono',monospace",fontVariantNumeric:"tabular-nums"}}>{v}{u&&<span style={{fontSize:10,color:"#475569",fontWeight:400}}> {u}</span>}</span>
      {show&&tip&&<div style={{position:"absolute",bottom:"100%",left:0,marginBottom:6,padding:"8px 12px",background:"#1e293b",border:"1px solid #334155",borderRadius:8,zIndex:100,minWidth:200,maxWidth:300,boxShadow:"0 8px 24px #00000060",pointerEvents:"none"}}>
        {tip.map((t,i)=><div key={i} style={{fontSize:10,color:t.c||"#94a3b8",marginBottom:i<tip.length-1?4:0,display:"flex",justifyContent:"space-between",gap:12}}>
          <span>{t.l}</span><span style={{fontFamily:"'JetBrains Mono',monospace",color:t.c||"#e2e8f0",fontWeight:600}}>{t.v}</span>
        </div>)}
      </div>}
    </div>
  );
}

function rc(v,g,b){return v>=g?"#34d399":v<=b?"#f87171":"#e2e8f0";}

function Spinner({size=12,color="#22d3ee"}){return <div style={{width:size,height:size,border:`2px solid ${color}33`,borderTop:`2px solid ${color}`,borderRadius:"50%",animation:"spin 0.8s linear infinite",flexShrink:0}}/>;}
function FreshBadge({fetched}){if(!fetched)return <span style={{fontSize:9,padding:"2px 6px",borderRadius:4,background:"#fbbf2412",color:"#fbbf24",border:"1px solid #fbbf2430"}}>静的データ</span>;const mins=Math.floor((Date.now()-fetched)/60000);return <span style={{fontSize:9,padding:"2px 6px",borderRadius:4,background:"#34d39912",color:"#34d399",border:"1px solid #34d39930"}}>{mins<1?"たった今":mins<60?`${mins}分前`:`${Math.floor(mins/60)}時間前`} 取得</span>;}

function QuarterlyView({q, mono}) {
  const yR=q.rev.map((v,i)=>i<4?null:((v-q.rev[i-4])/q.rev[i-4]*100));
  const yO=q.op.map((v,i)=>i<4?null:((v-q.op[i-4])/q.op[i-4]*100));
  const qO=q.op.map((v,i)=>i===0?null:((v-q.op[i-1])/Math.abs(q.op[i-1]||1)*100));
  const mx=Math.max(...q.opm),mn=Math.min(...q.opm),rg=mx-mn||1;
  const pts=q.opm.map((v,i)=>`${45+(i/(q.opm.length-1))*255},${10+((mx-v)/rg)*120}`);
  return(<>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:14}}>
      <div style={{padding:18,background:"#111827",borderRadius:12,border:"1px solid #1e293b"}}>
        <h3 style={{fontSize:10,color:"#64748b",margin:"0 0 12px",textTransform:"uppercase",letterSpacing:"0.05em"}}>四半期売上高</h3>
        <Bar data={q.rev.map((v,i)=>({v,l:q.qt[i]}))} h={130}/>
        <div style={{display:"flex",marginTop:4}}><div style={{flex:1,textAlign:"center",fontSize:9,color:"#475569",borderTop:"1px solid #1e293b30",paddingTop:4}}>{q.fy[0]}</div><div style={{flex:1,textAlign:"center",fontSize:9,color:"#475569",borderTop:"1px solid #1e293b30",paddingTop:4}}>{q.fy[4]}</div></div>
      </div>
      <div style={{padding:18,background:"#111827",borderRadius:12,border:"1px solid #1e293b"}}>
        <h3 style={{fontSize:10,color:"#64748b",margin:"0 0 12px",textTransform:"uppercase",letterSpacing:"0.05em"}}>営業利益率トレンド</h3>
        <svg viewBox="0 0 320 140" style={{width:"100%"}}>
          {[0,1,2,3,4].map(i=>{const y=10+i*30;return <g key={i}><line x1="35" y1={y} x2="310" y2={y} stroke="#1e293b" strokeDasharray="2,4"/><text x="30" y={y+4} fill="#475569" fontSize="9" textAnchor="end" fontFamily="JetBrains Mono,monospace">{(mx-(i/4)*rg).toFixed(1)}</text></g>;})}
          <polygon points={[...pts,`${45+255},130`,`45,130`].join(" ")} fill="url(#og)" opacity="0.3"/>
          <polyline points={pts.join(" ")} fill="none" stroke="#f472b6" strokeWidth="2.5" strokeLinejoin="round"/>
          {q.opm.map((v,i)=>{const x=45+(i/(q.opm.length-1))*255,y2=10+((mx-v)/rg)*120;return <g key={i}><circle cx={x} cy={y2} r="4" fill="#0a0e1a" stroke="#f472b6" strokeWidth="2"/><text x={x} y={y2-10} fill="#e2e8f0" fontSize="9" textAnchor="middle" fontFamily="JetBrains Mono,monospace" fontWeight="600">{v}%</text></g>;})}
          {q.qt.map((l,i)=><text key={i} x={45+(i/(q.qt.length-1))*255} y="140" fill="#475569" fontSize="8" textAnchor="middle">{l}</text>)}
          <defs><linearGradient id="og" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#f472b6" stopOpacity="0.4"/><stop offset="100%" stopColor="#f472b6" stopOpacity="0"/></linearGradient></defs>
        </svg>
      </div>
    </div>
    <div style={{background:"#111827",borderRadius:12,border:"1px solid #1e293b",overflow:"hidden"}}>
      <div style={{padding:"12px 18px",borderBottom:"1px solid #1e293b",display:"flex",justifyContent:"space-between"}}><h3 style={{fontSize:10,color:"#94a3b8",margin:0,fontWeight:600,textTransform:"uppercase"}}>四半期業績サマリー</h3><span style={{fontSize:10,color:"#475569"}}>十億円</span></div>
      <div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
        <thead><tr style={{borderBottom:"1px solid #1e293b"}}><th style={{padding:"10px 12px",textAlign:"left",fontSize:10,color:"#64748b"}}>指標</th>
          {q.qt.map((l,i)=><th key={i} style={{padding:"10px 8px",textAlign:"right",fontSize:10,fontFamily:mono,color:i>=4?"#e2e8f0":"#64748b",background:i>=4?"#22d3ee05":"transparent"}}>{q.fy[i]} {l}</th>)}
        </tr></thead>
        <tbody>
          {[{l:"売上高",d:q.rev},{l:"　YoY",d:yR,s:1},{l:"営業利益",d:q.op},{l:"　YoY",d:yO,s:1},{l:"純利益",d:q.np},{l:"営業利益率",d:q.opm,r:1},{l:"　QoQ 営業利益",d:qO,s:1}].map((row,ri)=><tr key={ri} style={{borderBottom:"1px solid #1e293b08"}}>
            <td style={{padding:row.s?"5px 12px":"10px 12px",color:row.s?"#64748b":"#94a3b8",fontWeight:row.s?400:500,fontSize:row.s?10:12,fontStyle:row.s?"italic":"normal"}}>{row.l}</td>
            {row.d.map((v,i)=><td key={i} style={{padding:row.s?"5px 8px":"10px 8px",textAlign:"right",fontFamily:mono,fontSize:row.s?10:12,background:i>=4?"#22d3ee05":"transparent",color:row.s?(v===null?"#334155":v>=0?"#34d399":"#f87171"):row.r?(v>=10?"#34d399":v>=7?"#e2e8f0":"#fbbf24"):"#e2e8f0",fontWeight:row.r?600:400}}>{v===null?"—":row.s?`${v>=0?"+":""}${v.toFixed(1)}%`:row.r?`${v.toFixed(1)}%`:v.toLocaleString()}</td>)}
          </tr>)}
        </tbody>
      </table></div>
    </div>
  </>);
}

